redis.setEx(`presence:${userId}`, 60, roomId);
db.mongo.messages.insert({ room_id: roomId, ts, sender: userId, text });
db.cassandra.daily_stats.upsert({ room_id: roomId, date: new Date().toDateString(), +1 });
